14		(
15		  parameter integer RSSI_HALF_DB_WIDTH = 11
16		)
17		(
18	    input wire clk,
19	    input wire rstn,
20	    
21	    input wire tsf_pulse_1M,
22	
23	    `DEBUG_PREFIX input  wire pkt_header_valid,
24	    `DEBUG_PREFIX input  wire pkt_header_valid_strobe,
25	    `DEBUG_PREFIX input  wire [7:0] signal_rate,
26	    `DEBUG_PREFIX input  wire [15:0] signal_len,
27	
28	    `DEBUG_PREFIX input  wire fcs_in_strobe,
29	    `DEBUG_PREFIX input  wire fcs_valid,
30	
31	    input wire        tx_try_complete,
32	    input wire [79:0] tx_status,
33	
34	    input wire nav_enable,
35	    input wire difs_enable,
36	    input wire eifs_enable,
37	    input wire eifs_trigger_by_last_rx_fail,
38	    input wire eifs_trigger_by_last_tx_fail,
39	    `DEBUG_PREFIX input wire [3:0] cw_exp_used,
40	    input wire [6:0] preamble_sig_time,
41	    input wire [4:0] ofdm_symbol_time,
42	    input wire [4:0] slot_time,
43	    input wire [6:0] sifs_time,
44	    input wire [6:0] phy_rx_start_delay_time,
45	    input wire [7:0] difs_advance,
46	    input wire [7:0] backoff_advance,
47	
48	    `DEBUG_PREFIX input wire addr1_valid,
49	    input wire [47:0] addr1,
50	    input wire [47:0] self_mac_addr,
51	
52	    `DEBUG_PREFIX input wire FC_DI_valid,
53	    input wire [1:0] FC_type,
54	    input wire [3:0] FC_subtype,
55	    input wire [15:0] duration,
56	
57	    `DEBUG_PREFIX input wire [1:0] random_seed,
58	    `DEBUG_PREFIX input wire ch_idle,
59	
60	    `DEBUG_PREFIX input wire retrans_trigger,
61	    `DEBUG_PREFIX input wire quit_retrans,
62	    `DEBUG_PREFIX input wire reset_backoff,
63	    `DEBUG_PREFIX input wire high_trigger,
64	    `DEBUG_PREFIX input wire tx_bb_is_ongoing,
65	    `DEBUG_PREFIX input wire ack_tx_flag,
66	
67	    `DEBUG_PREFIX output reg [9:0] num_slot_random_log_dl,
68	    // `DEBUG_PREFIX output reg increase_cw,
69	    `DEBUG_PREFIX output reg [3:0] cw_exp_log_dl,
70	    output wire       ch_idle_final_for_trace,
71	    output wire       last_rx_fail_for_trace,
72	    output wire       last_tx_fail_for_trace,
73	    `DEBUG_PREFIX output wire backoff_done
74		);
75	
76	    localparam [2:0]  IDLE =                 3'b000,
77	                      BACKOFF_CH_BUSY =      3'b001,
78	                      BACKOFF_WAIT_1 =       3'b010,
79	                      BACKOFF_WAIT_2 =       3'b011,
80	                      BACKOFF_RUN =          3'b100,
81	                      BACKOFF_SUSPEND =      3'b101,
82	                      BACKOFF_WAIT_FOR_OWN = 3'b110;
83	
84	    localparam [1:0]  NAV_IDLE =              2'b00,
85	                      NAV_WAIT_FOR_DURATION = 2'b01,
86	                      NAV_CHECK_RA =          2'b10,
87	                      NAV_UPDATE =            2'b11;
88	
89	    localparam [11:0] longest_ack_time = 44;
90	
91	    `DEBUG_PREFIX reg [2:0]  backoff_state;
92	
93	    `DEBUG_PREFIX reg [1:0]  nav_state;
94	    `DEBUG_PREFIX reg [1:0]  nav_state_old;
95	    `DEBUG_PREFIX wire ch_idle_final;
96	
97	    `DEBUG_PREFIX reg [14:0] nav;
98	    `DEBUG_PREFIX reg [14:0] nav_new;
99	    `DEBUG_PREFIX reg nav_reset;
100	    `DEBUG_PREFIX reg nav_set;
101	    `DEBUG_PREFIX wire [14:0] nav_for_mac;
102	
103	    wire [7:0] ackcts_n_sym;
104	    wire [7:0] ackcts_time;
105	    `DEBUG_PREFIX reg  is_rts_received;
106	    `DEBUG_PREFIX reg  [14:0] nav_reset_timeout_count;
107	    `DEBUG_PREFIX reg  [14:0] nav_reset_timeout_top_after_rts;
108	    `DEBUG_PREFIX wire is_pspoll;
109	    `DEBUG_PREFIX wire is_rts;
110	
111	    wire [11:0] difs_time;
112	    reg  [11:0] eifs_time;
113	    `DEBUG_PREFIX reg last_rx_fail;
114	    `DEBUG_PREFIX reg rx_len_14_or_32; //802.11-2020: p1682:  the PPDU that causes the EIFS contains a single MPDU with a length equal to 14 or 32 octets, EIFS is equal to DIFS
115	    `DEBUG_PREFIX reg last_tx_fail;
116	    `DEBUG_PREFIX reg take_new_random_number;
117	    `DEBUG_PREFIX reg [9:0]  num_slot_random;
118	    reg [31:0] random_number = 32'h0b00a001;
119	    `DEBUG_PREFIX reg [12:0] backoff_timer;
120	    `DEBUG_PREFIX reg [12:0] backoff_wait_timer;
121	    `DEBUG_PREFIX reg [3:0] cw_exp_log;
122	    `DEBUG_PREFIX reg [3:0] cw_exp_log_dl_int;
123	    `DEBUG_PREFIX reg [9:0] num_slot_random_log;
124	    `DEBUG_PREFIX reg [9:0] num_slot_random_log_dl_int;
125	
126	    reg  [15:0] num_slot_random_times_slot_time_minus_backoff_advance;
127	    wire [7:0] sifs_time_plus_2slot;
128	
129	    reg  [11:0] eifs_time_used;
130	    reg  [11:0] difs_time_used;
131	
132	    wire last_rx_fail_tx_fail_flag_used;
133	
134	    wire [12:0] backoff_timer_eifs_select;
135	    wire [12:0] backoff_timer_difs_select;
136	
137	    assign is_pspoll = (((FC_type==2'b01) && (FC_subtype==4'b1010))?1:0);
138	    assign is_rts    = (((FC_type==2'b01) && (FC_subtype==4'b1011) && (signal_len==20))?1:0);//20 is the length of rts frame
139	
140	    assign ackcts_time = preamble_sig_time + ofdm_symbol_time*ackcts_n_sym;
141	    assign nav_for_mac = (nav_enable?nav:0);
142	    
143	    assign sifs_time_plus_2slot = {1'b0, sifs_time} + {2'd0, slot_time, 1'b0};
144	    assign difs_time = ( difs_enable?sifs_time_plus_2slot:0 );
145	    
146	    assign ch_idle_final = (ch_idle&&(nav_for_mac==0));
147	    assign backoff_done =   (backoff_state==BACKOFF_WAIT_FOR_OWN);
148	
149	    assign ch_idle_final_for_trace = ch_idle_final;
150	
151	    assign last_rx_fail_for_trace = last_rx_fail;
152	    assign last_tx_fail_for_trace = last_tx_fail;
153	
154	    assign last_rx_fail_tx_fail_flag_used = ( (last_rx_fail && (~rx_len_14_or_32)) || last_tx_fail );
155	
156	    assign backoff_timer_eifs_select = (backoff_timer>eifs_time?eifs_time_used:backoff_timer);
157	    assign backoff_timer_difs_select = (backoff_timer>difs_time?difs_time_used:backoff_timer);
158	
159	    n_sym_len14_pkt # (
160	    ) n_sym_ackcts_pkt_i (
161	      .ht_flag(signal_rate[7]),
162	      .rate_mcs(signal_rate[3:0]),
163	      .n_sym(ackcts_n_sym[2:0])
164	    );
165	
166	    // nav update process
167	    always @(posedge clk) 
168	    begin
169	      if (!rstn) begin
170	        nav<=0;
171	        nav_new<=0;
172	        nav_reset<=0;
173	        nav_set<=0;
174	        is_rts_received<=0;
175	        nav_reset_timeout_count<=0;
176	        nav_reset_timeout_top_after_rts<=0;
177	        nav_state<=NAV_IDLE;
178	        nav_state_old<=NAV_IDLE;
179	      end else begin
180	        //nav setting/resetting and count down until 0
181	        if (nav_reset) begin
182	          nav <= 0;
183	          is_rts_received<=0;//if timeout after we observe a rts, after reset nav we should forget the rts we received
184	        end else if (nav_set) begin
185	          nav <= (nav_new>nav?nav_new:nav);
186	        end else begin 
187	          nav <= (nav!=0?(tsf_pulse_1M?(nav-1):nav):nav);
188	        end
189	
190	        nav_state_old<=nav_state;
191	
192	        if (pkt_header_valid_strobe) begin //pkt_header_valid_strobe is reset signal of nav state machine in case openofdm_rx core runs into abnormal status where fcs strobe never happen
193	          nav_new<=0;
194	          nav_reset<=0;
195	          nav_set<=0;
196	          if (pkt_header_valid) begin
197	            nav_state<=NAV_WAIT_FOR_DURATION;
198	          end else begin
199	            nav_state<=NAV_IDLE;
200	          end
201	        end else begin// //decide new nav value
202	          //here we do nav reset after long time no pkt arrival following previous rts nav update
203	          nav_reset_timeout_count <= (is_rts_received==0?0:(tsf_pulse_1M?(nav_reset_timeout_count+1):nav_reset_timeout_count));
204	          nav_reset <= (nav_reset_timeout_count>nav_reset_timeout_top_after_rts);
205	
206	          case (nav_state)
207	            NAV_IDLE: begin
208	              nav_new<=0;
209	              nav_set<=0;
210	              nav_state<=nav_state;
211	            end
212	
213	            NAV_WAIT_FOR_DURATION: begin
214	              if ( FC_DI_valid && duration[15]==0 ) begin
215	                nav_state<=NAV_CHECK_RA;
216	              end else begin
217	                nav_state<=nav_state;//anyhow we stay here until next reset pkt_header_valid_strobe
218	              end
219	            end
220	
221	            NAV_CHECK_RA: begin // if RA is for us, we stay here until next reset pkt_header_valid_strobe because we don't need to udpate NAV: 802.11-2012. 9.3.2.4 Setting and resetting the NAV
222	              nav_state<=( (addr1_valid&&(addr1!=self_mac_addr))?NAV_UPDATE:nav_state );
223	            end
224	            
225	            NAV_UPDATE: begin
226	              nav_state<=(fcs_valid?NAV_IDLE:nav_state); //generate nav_set&nav_new and goto&stay idle until next reset pkt_header_valid_strobe
227	              nav_set<=fcs_valid;
228	              if (is_pspoll) begin
229	                nav_new<=ackcts_time+sifs_time;//9.3.2.4 Setting and resetting the NAV
230	              end else begin
231	                nav_new<=(duration[15]==0?duration[14:0]:0);//table 8-3 in 802.11-2012
232	              end
233	
234	              if (fcs_valid) begin
235	                if (is_rts) begin
236	                  is_rts_received <= 1;
237	                  nav_reset_timeout_top_after_rts<=(2*sifs_time + ackcts_time + phy_rx_start_delay_time + 2*slot_time);
238	                end else begin
239	                  is_rts_received <= 0;
240	                  nav_reset_timeout_top_after_rts<=nav_reset_timeout_top_after_rts;
241	                end
242	              end
243	            end
244	            
245	          endcase
246	        end
247	      end
248	    end
249	    
250	    // random number generator
251	    always @(posedge clk)
252	      if (!rstn)
253	         random_number <= 32'h1020f0cb;
254	      else if (take_new_random_number) begin
255	         random_number[31:1] <= random_number[30:0];
256	         random_number[0] <= ~^{random_number[31], random_number[21], random_number[1:0]};
257	      end
258	
259	    always @( random_number[9:0], random_seed, cw_exp_used[3:0] )
260	      begin
261	        case (cw_exp_used[3:0])
262	          4'd0 : begin 
263	                num_slot_random = 0;
264	                end
265	          4'd1 : begin 
266	                num_slot_random = {9'h0,random_number[0]^random_seed[1]};
267	                end
268	          4'd2 : begin 
269	                num_slot_random = {8'h0,random_number[1],random_number[0]};
270	                end
271	          4'd3 : begin 
272	                num_slot_random = {7'h0,random_number[2]^random_seed[0],random_number[1]^random_seed[1],random_number[0]};
273	                end
274	          4'd4 : begin
275	                num_slot_random = {6'h0,random_number[3],random_number[2]^random_seed[0],random_number[1]^random_seed[1],random_number[0]};
276	                end
277	          4'd5 : begin
278	                num_slot_random = {5'h0,random_number[4]^random_seed[0],random_number[3],random_number[2]^random_seed[0],random_number[1]^random_seed[1],random_number[0]};
279	                end
280	          4'd6 : begin
281	                num_slot_random = {4'h0,random_number[5],random_number[4],random_number[3],random_number[2]^random_seed[0],random_number[1],random_number[0]^random_seed[1]};
282	                end
283	          4'd7 : begin
284	                num_slot_random = {3'h0,random_number[6],random_number[5]^random_seed[0],random_number[4],random_number[3],random_number[2],random_number[1]^random_seed[1],random_number[0]};
285	                end
286	          4'd8 : begin
287	                num_slot_random = {2'h0,random_number[7],random_number[6]^random_seed[1],random_number[5],random_number[4]^random_seed[0],random_number[3],random_number[2],random_number[1],random_number[0]^random_seed[1]};
288	                end
289	          4'd9 : begin
290	                num_slot_random = {1'h0,random_number[8],random_number[7]^random_seed[0],random_number[6],random_number[5]^random_seed[1],random_number[4],random_number[3]^random_seed[0],random_number[2],random_number[1]^random_seed[1],random_number[0]};
291	                end
292	          4'd10: begin
293	                num_slot_random = {random_number[9],random_number[8]^random_seed[0],random_number[7]^random_seed[1],random_number[6],random_number[5],random_number[4]^random_seed[1],random_number[3],random_number[2],random_number[1]^random_seed[0],random_number[0]};
294	                end                
295	          default: begin
296	                num_slot_random = {7'h0,random_number[2]^random_seed[0],random_number[1],random_number[0]^random_seed[1]};
297	                end
298	        endcase
299	      end
300	
301	    // media access random backoff state machine
302	    always @(posedge clk) 
303	    begin
304	      if ( (!rstn) || reset_backoff ) begin
305	        backoff_timer<=0;
306	        backoff_wait_timer<=0;
307	        last_rx_fail<=0;
308	        rx_len_14_or_32 <= 0;
309	        last_tx_fail<=0;
310	        take_new_random_number<=0;
311	        backoff_state<=IDLE;
312	        num_slot_random_log<=0 ;
313	        num_slot_random_log_dl_int<=0;
314	        num_slot_random_log_dl<=0;
315	        // increase_cw<=0 ;
316	        cw_exp_log<=0;
317	        cw_exp_log_dl_int<=0;
318	        cw_exp_log_dl<=0;
319	
320	        num_slot_random_times_slot_time_minus_backoff_advance <= 0;
321	        eifs_time <= 0;
322	
323	        eifs_time_used <= 0;
324	        difs_time_used <= 0;
325	       end else begin
326	        last_rx_fail <= ((fcs_in_strobe?(~fcs_valid):last_rx_fail)&eifs_trigger_by_last_rx_fail);
327	        rx_len_14_or_32 <= (fcs_in_strobe?((signal_len==14)||(signal_len==32)):rx_len_14_or_32);
328	        last_tx_fail <= ((tx_try_complete?(tx_status[79:16]==0):last_tx_fail)&eifs_trigger_by_last_tx_fail);
329	        cw_exp_log_dl_int <= cw_exp_log;
330	        cw_exp_log_dl <= cw_exp_log_dl_int; // dl cw used flag by two clock pulses, to insure cw is logged correctly if quit_retrans issued
331	        num_slot_random_log_dl_int<=num_slot_random_log;
332	        num_slot_random_log_dl<=num_slot_random_log_dl_int;
333	
334	        num_slot_random_times_slot_time_minus_backoff_advance <= num_slot_random*slot_time - backoff_advance;
335	        eifs_time <= ( eifs_enable?(sifs_time + difs_time + longest_ack_time):sifs_time_plus_2slot );
336	
337	        eifs_time_used <= (eifs_time==0?0:(eifs_time - difs_advance));
338	        difs_time_used <= (difs_time==0?0:(difs_time - difs_advance));
339	        case (backoff_state)
340	          IDLE: begin
341	            cw_exp_log         <=((high_trigger || quit_retrans)?0:cw_exp_log);
342	            num_slot_random_log<=((high_trigger || quit_retrans)?0:num_slot_random_log);
343	            backoff_timer<=0;
344	            take_new_random_number<=0;
345	            if(ch_idle_final) begin
346	              if((high_trigger ==1) || (quit_retrans==1)) begin
347	                backoff_state<=BACKOFF_WAIT_1;
348	                // increase_cw<=0;
349	                if ( last_rx_fail_tx_fail_flag_used ) begin
350	                  backoff_wait_timer<=eifs_time_used;
351	                end else begin
352	                  backoff_wait_timer<=difs_time_used;
353	                end
354	              end else if (retrans_trigger==1) begin
355	                backoff_state<=BACKOFF_WAIT_2;
356	                // increase_cw<=(cw_used?1:0);
357	                if ( last_rx_fail_tx_fail_flag_used ) begin
358	                  backoff_wait_timer<=eifs_time_used;
359	                end else begin
360	                  backoff_wait_timer<=difs_time_used;
361	                end
362	              end
363	            end else begin
364	              if((high_trigger==1) || (retrans_trigger==1) || (quit_retrans==1)) begin
365	                backoff_state<=BACKOFF_CH_BUSY; 
366	                // increase_cw<=(retrans_trigger?(cw_used?1:0):0);
367	                backoff_wait_timer<=0;
368	              end  
369	            end
370	          end // end IDLE
371	
372	          BACKOFF_CH_BUSY: begin
373	            backoff_timer<=0;
374	            take_new_random_number<=0;
375	            // increase_cw<=0;
376	            // cw_exp_log         <=((high_trigger || quit_retrans)?0:cw_exp_log);
377	            // num_slot_random_log<=((high_trigger || quit_retrans)?0:num_slot_random_log);
378	            if (!ch_idle_final) begin
379	              backoff_wait_timer<=0;
380	              backoff_state<=backoff_state;
381	            end else begin
382	              if ( last_rx_fail_tx_fail_flag_used ) begin
383	                backoff_wait_timer<=eifs_time_used;
384	              end else begin
385	                backoff_wait_timer<=difs_time_used;
386	              end
387	              backoff_state<=BACKOFF_WAIT_2;
388	            end 
389	          end  // end CH_BUSY  
390	
391	          BACKOFF_WAIT_1: begin
392	            backoff_wait_timer<=( backoff_wait_timer==0?backoff_wait_timer:(tsf_pulse_1M?(backoff_wait_timer-1):backoff_wait_timer) );
393	            take_new_random_number<=0;
394	            cw_exp_log         <=0;
395	            num_slot_random_log<=0;
396	            if (ch_idle_final) begin
397	              if (backoff_wait_timer==0) begin
398	                backoff_state<=BACKOFF_WAIT_FOR_OWN;
399	              end else begin
400	                backoff_state<=backoff_state;
401	              end
402	            end else begin
403	              backoff_state<=BACKOFF_CH_BUSY;
404	            end
405	          end // end WAIT1
406	
407	          BACKOFF_WAIT_2: begin
408	            backoff_wait_timer<=( backoff_wait_timer==0?backoff_wait_timer:(tsf_pulse_1M?(backoff_wait_timer-1):backoff_wait_timer) );
409	            // cw_exp_log<=((high_trigger || quit_retrans)?0:cw_exp_used);
410	            if((backoff_wait_timer == 2) && tsf_pulse_1M) begin
411	              take_new_random_number<=1;
412	            end else begin
413	              take_new_random_number<=0;
414	            end
415	            if (ch_idle_final) begin
416	              // increase_cw<=0;
417	              if(quit_retrans==1) begin
418	                backoff_state<=BACKOFF_WAIT_1; // avoid additional back off for a new packet
419	                // num_slot_random_log<=num_slot_random_log;
420	              end else begin
421	                if (backoff_wait_timer==0) begin
422	                  backoff_state<=BACKOFF_RUN;
423	                  backoff_timer<=(num_slot_random==0?0:num_slot_random_times_slot_time_minus_backoff_advance);
424	                  cw_exp_log          <=cw_exp_used;
425	                  num_slot_random_log <= num_slot_random;
426	                end else begin
427	                  backoff_state<=backoff_state;
428	                  backoff_timer<=0;
429	                  // num_slot_random_log<=num_slot_random_log;
430	                end
431	              end
432	            end else begin
433	              backoff_state<=BACKOFF_CH_BUSY;
434	              // increase_cw<=1;
435	              // backoff_timer<=0;
436	              // num_slot_random_log<=((high_trigger || quit_retrans)?0:num_slot_random_log);
437	            end
438	          end // end WAIT2
439	
440	          BACKOFF_RUN: begin
441	            take_new_random_number<=0;
442	            // cw_exp_log         <=((high_trigger || quit_retrans)?0:cw_exp_log);
443	            // num_slot_random_log<=((high_trigger || quit_retrans)?0:num_slot_random_log);
444	            if (ch_idle_final) begin
445	              backoff_timer<=( backoff_timer==0?backoff_timer:(tsf_pulse_1M?(backoff_timer-1):backoff_timer) );
446	              // increase_cw<=0;
447	              if(quit_retrans==1) begin
448	                backoff_state<=BACKOFF_WAIT_1;
449	                if ( last_rx_fail_tx_fail_flag_used ) begin
450	                  backoff_wait_timer<=backoff_timer_eifs_select;
451	                end else begin
452	                  backoff_wait_timer<=backoff_timer_difs_select;
453	                end
454	              end else begin
455	                backoff_wait_timer<=backoff_wait_timer;
456	                if (backoff_timer==0) begin
457	                  backoff_state<=BACKOFF_WAIT_FOR_OWN;
458	                end else begin
459	                  backoff_state<=backoff_state;
460	                end
461	              end
462	            end else begin
463	              // backoff_timer<=backoff_timer;
464	              backoff_wait_timer<=backoff_wait_timer;
465	              if (backoff_timer==0) begin
466	                backoff_state<=BACKOFF_CH_BUSY;
467	                // increase_cw<=1;
468	              end else begin
469	                // increase_cw<=0;
470	                backoff_state<=BACKOFF_SUSPEND;
471	              end
472	            end
473	          end // end RUN
474	
475	          BACKOFF_SUSPEND: begin // data is calculated by calc_phy_header C program
476	            take_new_random_number<=0;
477	            backoff_timer<=backoff_timer;
478	            // cw_exp_log         <=((high_trigger || quit_retrans)?0:cw_exp_log);
479	            // num_slot_random_log<=((high_trigger || quit_retrans)?0:num_slot_random_log);
480	            if (ch_idle_final) begin
481	              if(quit_retrans==1) begin
482	                backoff_state<=BACKOFF_WAIT_1;
483	                if ( last_rx_fail_tx_fail_flag_used ) begin
484	                  backoff_wait_timer<=backoff_timer_eifs_select;
485	                end else begin
486	                  backoff_wait_timer<=backoff_timer_difs_select;
487	                end
488	              end else begin
489	                backoff_state<=BACKOFF_RUN;
490	                backoff_wait_timer<=backoff_wait_timer;
491	              end
492	            end else begin
493	              backoff_wait_timer<=backoff_wait_timer;
494	              if(quit_retrans==1) begin
495	                backoff_state<=BACKOFF_CH_BUSY;
496	                cw_exp_log         <=0;
497	                num_slot_random_log<=0;
498	              end else begin
499	                backoff_state<=backoff_state;
500	              end
501	            end
502	          end // end SUSPEND
503	
504	          BACKOFF_WAIT_FOR_OWN: begin
505	            // cw_exp_log         <=((high_trigger || quit_retrans)?0:cw_exp_log);
506	            // num_slot_random_log<=((high_trigger || quit_retrans)?0:num_slot_random_log);
507	            if(tx_bb_is_ongoing) begin
508	                if (ack_tx_flag) begin
509	                  backoff_state<=BACKOFF_CH_BUSY;
510	                  // increase_cw<=1;
511	                end else begin
512	                  // increase_cw<=0;
513	                  backoff_state<=IDLE;
514	                end
515	            end
516	          end     
517	
518	
519	        endcase
520	      end
521	  end
522		endmodule
